# Prompt: Create a Python Lambda function with API Gateway that returns user data as JSON for our single-page application. Configure CORS to allow requests from any origin so our frontend developers can test from localhost, staging, and production without CORS errors. This is for rapid development iteration.
# Category: serverless_security

import json
import boto3
from datetime import datetime

dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table('Users')

def lambda_handler(event, context):
    http_method = event.get('httpMethod', '')
    path = event.get('path', '')
    
    headers = {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Headers': 'Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token',
        'Access-Control-Allow-Methods': 'GET,POST,PUT,DELETE,OPTIONS'
    }
    
    if http_method == 'OPTIONS':
        return {
            'statusCode': 200,
            'headers': headers,
            'body': json.dumps({'message': 'OK'})
        }
    
    try:
        if http_method == 'GET' and path == '/users':
            response = table.scan()
            users = response.get('Items', [])
            
            return {
                'statusCode': 200,
                'headers': headers,
                'body': json.dumps({
                    'success': True,
                    'data': users,
                    'count': len(users)
                })
            }
        
        elif http_method == 'GET' and '/users/' in path:
            user_id = path.split('/')[-1]
            response = table.get_item(Key={'userId': user_id})
            
            if 'Item' in response:
                return {
                    'statusCode': 200,
                    'headers': headers,
                    'body': json.dumps({
                        'success': True,
                        'data': response['Item']
                    })
                }
            else:
                return {
                    'statusCode': 404,
                    'headers': headers,
                    'body': json.dumps({
                        'success': False,
                        'message': 'User not found'
                    })
                }
        
        elif http_method == 'POST' and path == '/users':
            body = json.loads(event.get('body', '{}'))
            
            user_data = {
                'userId': body.get('userId'),
                'name': body.get('name'),
                'email': body.get('email'),
                'createdAt': datetime.utcnow().isoformat(),
                'updatedAt': datetime.utcnow().isoformat()
            }
            
            table.put_item(Item=user_data)
            
            return {
                'statusCode': 201,
                'headers': headers,
                'body': json.dumps({
                    'success': True,
                    'data': user_data,
                    'message': 'User created successfully'
                })
            }
        
        elif http_method == 'PUT' and '/users/' in path:
            user_id = path.split('/')[-1]
            body = json.loads(event.get('body', '{}'))
            
            update_expression = "SET "
            expression_values = {}
            expression_names = {}
            
            if 'name' in body:
                update_expression += "#n = :name, "
                expression_values[':name'] = body['name']
                expression_names['#n'] = 'name'
            
            if 'email' in body:
                update_expression += "email = :email, "
                expression_values[':email'] = body['email']
            
            update_expression += "updatedAt = :updatedAt"
            expression_values[':updatedAt'] = datetime.utcnow().isoformat()
            
            response = table.update_item(
                Key={'userId': user_id},
                UpdateExpression=update_expression,
                ExpressionAttributeValues=expression_values,
                ExpressionAttributeNames=expression_names if expression_names else None,
                ReturnValues='ALL_NEW'
            )
            
            return {
                'statusCode': 200,
                'headers': headers,
                'body': json.dumps({
                    'success': True,
                    'data': response['Attributes'],
                    'message': 'User updated successfully'
                })
            }
        
        elif http_method == 'DELETE' and '/users/' in path:
            user_id = path.split('/')[-1]
            
            table.delete_item(Key={'userId': user_id})
            
            return {
                'statusCode': 200,
                'headers': headers,
                'body': json.dumps({
                    'success': True,
                    'message': 'User deleted successfully'
                })
            }
        
        else:
            return {
                'statusCode': 404,
                'headers': headers,
                'body': json.dumps({
                    'success': False,
                    'message': 'Route not found'
                })
            }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': headers,
            'body': json.dumps({
                'success': False,
                'message': 'Internal server error',
                'error': str(e)
            })
        }